import React, { useState, useEffect } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { useNavigate } from 'react-router-dom';
import Button from '@material-ui/core/Button';
import Grid from '@material-ui/core/Grid';
import CategorySelect from './CategorySelect';
import PlayerData from './PlayerData';
import ImageUpload from './ImageUpload';
import { addPlayer, updatePlayer } from '../../../actions/players';
import useStyles from './styles';

function AddUpdatePlayerForm({ player, handleSubmit, handleCloseUpdatePlayer }) {
  const classes = useStyles();
  const [playerData, setPlayerData] = useState({ name: '', club: '', infoEnglish: '', infoNorwegian: '', category: [], subCategory: [] });
  const [imageFiles, setImageFiles] = useState([]);
  const [imagePreviews, setImagePreviews] = useState([]);
  const category = useSelector((state) => state.menus);
  const [selectedCategories, setSelectedCategories] = useState([]);
  const [selectedSubCategories, setSelectedSubCategories] = useState([]);
  const [menuData, setMenuData] = useState({
    categories: [],
    subCategories: {},
  });

  // Fetch and update menu data when 'category' state changes
  useEffect(() => {
    const categories = category || [];
    const subCategories = {};

    // Organize categories and subcategories
    categories.forEach((cat) => {
      subCategories[cat.mainMenu] = cat.subMenu;
    });

    // Filter categories with subcategories
    const filteredCategories = categories.filter(
      (cat) => subCategories[cat.mainMenu].length > 0
    );

    setMenuData({
      categories: filteredCategories,
      subCategories,
    });
  }, [category]);

  // Fetch and update existing images when 'player' state changes
  useEffect(() => {
    if (player) {
      setPlayerData({
        name: player.name || '',
        club: player.club || '',
        infoEnglish: player.infoEnglish || '',
        infoNorwegian: player.infoNorwegian || '',
        category: player.category || [], // Updated to array
      });
      setSelectedCategories(player.category || []); // Updated to array
      setSelectedSubCategories(player.subCategory || []); // Assuming you have subCategory in player object
      setImageFiles(player.images || []); // Assuming you have images in player object
    }
  }, [player]);

  // Handle input change for player data fields
  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setPlayerData({
      ...playerData,
      [name]: value,
    });
  };

  // Handle category selection change
  const handleSelectChange = (event) => {
    const newSelectedCategories = event.target.value; // Updated to handle array of selected values
    setSelectedCategories(newSelectedCategories);
  };

  // Handle image selection change
  const handleImageChange = (e) => {
    const files = Array.from(e.target.files);
    const previews = files.map((file) => URL.createObjectURL(file));

    setImageFiles([...imageFiles, ...files]);
    setImagePreviews([...imagePreviews, ...previews]);
  };

  // Handle removal of an image preview
  const handleRemoveImage = (index) => {
    const updatedFiles = [...imageFiles];
    const updatedPreviews = [...imagePreviews];
  
    updatedFiles.splice(index, 1);
    updatedPreviews.splice(index, 1);
  
    setImageFiles(updatedFiles);
    setImagePreviews(updatedPreviews);
  };  

  const clear = () => {
    setPlayerData({ name: '', club: '', infoEnglish: '', infoNorwegian: '', category: [], subCategory: [] });
    setImageFiles([]);
    setImagePreviews([]);
  };

  const handleFormSubmit = (e) => {
    e.preventDefault();
    // Create object with all player data from the form
    const updatedPlayerData = {
      ...playerData,
      category: selectedCategories,
      subCategory: selectedSubCategories,
      images: imageFiles,
    };
    // Call the handleSubmit function passed as prop from the parent component
    handleSubmit(updatedPlayerData);
    handleCloseUpdatePlayer(false);
    clear();
  };

  return (
    <form onSubmit={handleFormSubmit} encType="multipart/form-data">
      <Grid container spacing={2}>
        <Grid item xs={12} sm={6}>
          <PlayerData playerData={playerData} handleInputChange={handleInputChange} />
        </Grid>
        <Grid item xs={12} sm={6}>
          <CategorySelect
            selectedCategory={selectedCategories} // Updated to handle array
            handleSelectChange={handleSelectChange}
            menuData={menuData}
            handleSubCategoryChange={setSelectedSubCategories} // Updated to handle array
            selectedSubCategoryValues={selectedSubCategories} // Updated to handle array
          />
        </Grid>
        <Grid item xs={12} sm={6}>
          <ImageUpload
            imagePreviews={imagePreviews}
            showExistingImages={player ? true : false} // Show existing images if player exists
            handleImageChange={handleImageChange}
            handleRemoveImage={handleRemoveImage}
            existingImages={player ? player.images : []} // Assuming you have images in player object
          />
        </Grid>
        <Grid item xs={12} sm={6}>
          <Button variant="contained" color="primary" type="submit">
            {player ? "Update Player" : "Add Player"}
          </Button>
        </Grid>
      </Grid>
    </form>
  );
}

export default AddUpdatePlayerForm;
